arguments.new_str:
using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // In .NET 9, ZipArchiveEntry now sets the UTF-8 flag in the entry header.
        // The legacy Java consumer reads filenames in Shift-JIS, so we must
        // explicitly specify Shift-JIS encoding to suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("Shift-JIS");

        using var stream = new FileStream("data.zip", FileMode.Create);
        using var archive = new ZipArchive(stream, ZipArchiveMode.Create, leaveOpen: false, entryNameEncoding: shiftJis);
        archive.CreateEntry("レポート/月次.csv");  // Japanese path
        archive.CreateEntry("données/résumé.txt"); // French accented
    }
}

